enum Mode { Manual, SemiAuto, FullAuto }

void RunMode(Mode mode)
{
    switch (mode)
    {
        case Mode.Manual:
            Print("手动模式: 请操作工手动调节温度旋钮");
            break;
        case Mode.SemiAuto:
            Print("半自动模式: 根据预设配方自动控温");
            break;
        case Mode.FullAuto:
            Print("全自动模式: 传感器反馈实时调节");
            break;
    }
}

RunMode(Mode.Manual);
RunMode(Mode.SemiAuto);
